const qs = $json.query;

// ----- 1. Paramètres entrés ou valeurs par défaut
const bedrooms = parseInt(qs.bedrooms ?? 2, 10);
const basePrice = 80 + (bedrooms - 1) * 20 + Math.random() * 20;   // ADR médian
const p50 = Math.round(basePrice);
const p75 = Math.round(basePrice * 1.25);

const occ = 60 + Math.random() * 25;            // taux d'occupation %
const annual = Math.round(p50 * (occ / 100) * 365);

// ----- 2. Mock listings comparables
const comps = Array.from({ length: 4 }).map((_, i) => ({
  name: `Listing démo #${i + 1}`,
  adr: Math.round(basePrice + (Math.random() * 30 - 15)),
  occ: Math.round(occ + (Math.random() * 10 - 5)),
  dist: Number((Math.random() * 4 + 0.5).toFixed(1)), // 0,5 ⇒ 4,5 km
  src: ["Airbnb", "Booking.com", "Abritel"][i % 3],
  img: `https://picsum.photos/seed/mock${i}/100/80`,
}));

// ----- 3. Payload final
return {
  json: {
    medianPrice: p50,
    p75Price: p75,
    annualRevenue: annual,
    seasonality: [150, 140, 130, 120, 110, 100, 90, 80, 95, 110, 130, 145],
    comps,
  },
};

