// Récupère les données de la query du webhook
const query = $input.item.json.query;

// Prépare les arguments pour le script MCP
const args = {
  location: query.address,
  // Convertit le nombre de chambres (string) en 'adults' (number)
  adults: parseInt(query.bedrooms) || 1 // Met 1 par défaut si la conversion échoue
};

// Gère le prix optionnel (convertit en nombre si non vide, sinon null)
const price = query.price;
if (price && price !== "") {
  args.maxPrice = parseFloat(price);
}

// Définit le nom de l'outil à appeler
const toolName = "airbnb_search";

// Construit l'objet payload final
const payload = {
  params: {
    name: toolName,
    arguments: args
  }
};

// Renvoie le payload structuré pour le nœud suivant
// n8n attend un tableau d'objets { json: ... }
return [{ json: payload }];

// Chemin vers le script DANS le conteneur n8n
const scriptPath = '/mcp-code/dist/index.js';

// Détermine si on ignore robots.txt (tu peux rendre ça dynamique si besoin)
const ignoreRobots = true; // ou false, ou récupérer depuis une étape précédente
const ignoreRobotsFlag = ignoreRobots ? '--ignore-robots-txt' : '';

// Récupère l'objet payload de l'étape précédente
const payload = $input.item.json;

// Convertit l'objet payload en chaîne JSON
const stdinJsonString = JSON.stringify(payload);

// Échappe les apostrophes simples pour la commande 'echo'
const escapedStdinJson = stdinJsonString.replace(/'/g, "'\\''");

// Construit la commande shell finale
const command = `echo '${escapedStdinJson}' | node ${scriptPath} ${ignoreRobotsFlag}`;

// Renvoie la commande prête à être exécutée
return [{ json: { command: command } }];

// Récupère la sortie standard (stdout) du nœud précédent
const stdout = $input.item.json.stdout;
let parsedOutput = {};

try {
  // Tente de parser la sortie JSON
  parsedOutput = JSON.parse(stdout);
} catch (error) {
  // Gère les erreurs si stdout n'est pas du JSON valide
  console.error("Erreur lors du parsing de la sortie MCP:", error);
  // Renvoie l'erreur ou un objet vide/spécifique
  parsedOutput = { error: "Failed to parse MCP output", rawOutput: stdout };
}

// Renvoie le résultat parsé
return [{ json: parsedOutput }];

// ------------------------------------------
//  Entrée :  HTTP Request             ➜ items[0].json
//            {
//              address, adults,
//              medianPrice, p75Price,
//              annualRevenue, comps:[{name,price,url}]
//            }
// ------------------------------------------

const data = items[0].json;

// --- 1. Seasonality mock (p75 - 10 €) ----
data.seasonality = Array(12).fill(Math.max(data.p75Price - 10, 0));

// --- 2. Remap comps  ----------------------
data.comps = (data.comps || []).map((c, i) => ({
  name: c.name,
  adr:  c.price,                // renommage
  occ:  60,                     // % d'occ. fixe pour l'instant
  dist: 0,                      // km : à calculer plus tard
  src:  "Airbnb",
  img:  c.img || `https://picsum.photos/seed/mock${i}/100/80`,
}));

// --- 3. Nettoyage & sortie ---------------
return [{ json: data }];
